class TaskService{constructor(){this.apiUrl="api.php"}async _request(t){try{const e=await fetch(this.apiUrl,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(t)});return await e.json()}catch(t){return{status:"error",message:"Lỗi kết nối server"}}}async fetchMyTasks(t){return await this._request({action:"fetch_my_tasks",userId:t})}async createTask(t){return await this._request({action:"create_task",title:t.title,quadrant:t.quadrant,startTime:t.startTime,endTime:t.endTime,assigneeId:t.assigneeId})}async updateStatus(t,e){return await this._request({action:"update_task_status",id:t,status:e})}}export default new TaskService;